+function joinConfigPath(path: string, name: string, format: string): string {
+  const file = format === ".rc" ? `.${name}rc` : `${name}${format}`;
+  const separator = path.endsWith("/") || path.endsWith("\\\\") ? "" : "/";
+  return `${path}${separator}${file}`;
