+async function configFileExists(path: string): Promise<boolean> {
+  try {
+    await readConfigFile(path);
+    return true;
+  } catch (error) {
+    if ((error as { code?: string }).code === "ENOENT" ||
+      (error as { name?: string }).name === "NotFound") {
+      return false;
+    }
+    throw error;
+  }
+}
+
+async function readConfigFile(path: string): Promise<string> {
+  // dnt-shim-ignore
+  const runtime = globalThis as any;
+  if (runtime.Deno) {
+    return await runtime.Deno.readTextFile(path);
+  }
+  const fs = await import("node:fs/promises");
+  return await fs.readFile(path, "utf8");
+}
+
+function parseConfig(content: string, path: string): Record<string, unknown> {
+  if (path.endsWith(".rc")) {
+    return parseRc(content);
+  }
+  return JSON.parse(content);
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\\r?\
/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const index = line.indexOf("=");
+    if (index < 1) throw new TypeError(`Invalid RC line: ${rawLine}`);
+    const key = line.slice(0, index).trim();
+    let value = line.slice(index + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new TypeError(`Unterminated quoted value: ${rawLine}`);
+      }
+      value = value.slice(1, -1);
+    }
+    result[camelCaseConfigKey(key)] = coerceRcValue(value);
+  }
+  return result;
+}
+
+function coerceRcValue(value: string): string | number | boolean {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) {
+    return Number(value);
+  }
+  return value;
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): ConfigValues {
+  const result: ConfigValues = {};
+  for (const [rawKey, child] of Object.entries(value)) {
+    const key = prefix
+      ? `${prefix}.${camelCaseConfigKey(rawKey)}`
+      : camelCaseConfigKey(rawKey);
+    if (isPlainObject(child)) {
+      Object.assign(result, flattenConfig(child, key));
+    } else {
+      result[key] = child;
+    }
+  }
+  return result;
+}
+
+function camelCaseConfigKey(key: string): string {
+  return key.replace(/-([a-zA-Z0-9])/g, (_match, letter: string) =>
+    letter.toUpperCase());
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  if (!value || typeof value !== "object" || Array.isArray(value)) return false;
+  const prototype = Object.getPrototypeOf(value);
+  return prototype === Object.prototype || prototype === null;
+}
