+function expandDottedValues(values: Record<string, unknown>): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, value] of Object.entries(values)) {
+    const parts = key.split(".");
+    let target = result;
+    for (let index = 0; index < parts.length - 1; index++) {
+      target = (target[parts[index]] ??= {}) as Record<string, unknown>;
+    }
+    target[parts.at(-1) as string] = value;
+  }
+  return result;
+}
+
+function deepMerge(
+  target: Record<string, unknown>,
+  source: Record<string, unknown>,
+): Record<string, unknown> {
+  for (const [key, value] of Object.entries(source)) {
+    if (isPlainObject(value) && isPlainObject(target[key])) {
+      deepMerge(target[key] as Record<string, unknown>, value);
+    } else {
+      target[key] = value;
+    }
+  }
+  return target;
+}
